public CanShowSdfResp canShowSdf(CanShowSdfReq req) throws TException {
    Preconditions.checkArgument(req != null, "请求参数为空");
    Preconditions.checkArgument(CollectionUtils.size(req.getDdAdAccountIds()) <= 1000, "单次请求inner数量超过1000");
    Preconditions.checkArgument(CollectionUtils.size(req.getDpPoiIds()) <= 1000, "单次请求门店数量超过1000");

    List<Partner> partners = new ArrayList<>();
    if (CollectionUtils.isNotEmpty(req.getDdAdAccountIds())) {
        partners.addAll(req.getDdAdAccountIds().stream().map(e -> new Partner(e, PartnerType.DD_SHOP_ACCOUNT.getIntValue())).collect(Collectors.toList()));
        partners.addAll(req.getDdAdAccountIds().stream().map(e -> new Partner(e, PartnerType.DD_UNIFIED_ACCOUNT.getIntValue())).collect(Collectors.toList()));
    }
    if (CollectionUtils.isNotEmpty(req.getDpPoiIds())) {
        partners.addAll(req.getDpPoiIds().stream().map(e -> new Partner(e, PartnerType.DP_POI.getIntValue())).collect(Collectors.toList()));
    }
    if (req.getMtAccountId() > 0) {
        partners.add(new Partner(req.getMtAccountId(), PartnerType.KDB.getIntValue()));
    }

    Map<Partner, SdfAdAccountActivity> partnerInUseSdfConfigMap = adAccountSdfAppService.queryPartnerInUseSdfConfig(partners);
    Set<Partner> configPartners = partnerInUseSdfConfigMap.keySet();
    List<Partner> signPartners = adAccountSdfAppService.querySdfSignPartners(partners);

    return new CanShowSdfResp().setResult(ResultV2Util.success())
            .setCanMtAccountShow(configPartners.stream().anyMatch(e -> e.getPartnerType() == PartnerType.KDB.getIntValue()))
            .setCanShowDpPoiIds(configPartners.stream().filter(e -> e.getPartnerType() == PartnerType.DP_POI.getIntValue()).map(Partner::getPartnerId).collect(Collectors.toSet()))
            .setCanShowDdAdAccountIds(signPartners.stream().filter(e -> PartnerType.isDDAccount(e.getPartnerType())).map(Partner::getPartnerId).collect(Collectors.toSet()))
            .setBenefitMap(getBenefitRuleInfoMap(partnerInUseSdfConfigMap));
}

private Map<PartnerDTO, SdfBenefitRuleDTO> getBenefitRuleInfoMap(Map<Partner, SdfAdAccountActivity> partnerInUseSdfConfigMap) {
    if (MapUtils.isEmpty(partnerInUseSdfConfigMap)) {
        return Collections.emptyMap();
    }
    Map<PartnerDTO, SdfBenefitRuleDTO> configInfoDTOMap = new HashMap<>();
    for (Map.Entry<Partner, SdfAdAccountActivity> entry : partnerInUseSdfConfigMap.entrySet()) {
        SdfBenefitRule sdfBenefitRule = JsonUtil.parse(entry.getValue().getBenefitStrategy(), SdfBenefitRule.class);
        PartnerDTO partnerDto = new PartnerDTO();
        partnerDto.setPartnerId(entry.getKey().getPartnerId());
        partnerDto.setPartnerType(entry.getKey().getPartnerType());
        configInfoDTOMap.put(partnerDto, SdfBenefitRule.convertToSdfBenefitRuleDTO(sdfBenefitRule));
    }
    return configInfoDTOMap;
}

