        try {
            CommenRequestParamVO requestParamVO = homePageCommenService.buildCommenRequestParamVO(request);
            long wmPoiId = requestParamVO.getWmPoiId();
            if (wmPoiId <= 0) {
                return MiscUtils.getReturnMessage(1, "参数错误", null);
