            JSONObject data = homePageCommenService.getBusinessRelInfo(requestParamVO, BusinessLineConstant.NOTICE_CENTER, waitTime);
            //newNoticeGray 灰度已经全量，永远为true
            data.put("newNoticeGray", true);
