public class SdfBenefitRule {
    private SdfCouponInfo sdfCouponInfo;
    private List<SdfRedPackStage> sdfRedPackStageRules;

    public SdfCouponInfo getSdfCouponInfo() {
        return sdfCouponInfo;
    }

    public void setSdfCouponInfo(SdfCouponInfo sdfCouponInfo) {
        this.sdfCouponInfo = sdfCouponInfo;
    }

    public List<SdfRedPackStage> getSdfRedPackStageRules() {
        return sdfRedPackStageRules;
    }

    public void setSdfRedPackStageRules(List<SdfRedPackStage> sdfRedPackStageRules) {
        this.sdfRedPackStageRules = sdfRedPackStageRules;
    }

    public static SdfBenefitRuleDTO convertToSdfBenefitRuleDTO(SdfBenefitRule rule) {
        if (rule == null) {
            return null;
        }
        SdfBenefitRuleDTO ruleDTO = new SdfBenefitRuleDTO();
        if (!CollectionUtils.isEmpty(rule.getSdfRedPackStageRules())) {
            List<SdfRedPackStageDTO> redPackStageDTOList = new ArrayList<>();
            for (SdfRedPackStage redPackStage : rule.getSdfRedPackStageRules()) {
                SdfRedPackStageDTO redPackStageDTO = new SdfRedPackStageDTO();
                redPackStageDTO.setRatio(redPackStage.getRatio().toString());
                redPackStageDTO.setStartOffsetDays(redPackStage.getStartOffsetDays());
                redPackStageDTO.setEndOffsetDays(redPackStage.getEndOffsetDays());
                redPackStageDTO.setStartDate(redPackStage.getStartDate() == null ? 0 : redPackStage.getStartDate());
                redPackStageDTO.setEndDate(redPackStage.getEndDate() == null ? 0 : redPackStage.getEndDate());
                redPackStageDTOList.add(redPackStageDTO);
            }
            ruleDTO.setSdfRedPackStageRules(redPackStageDTOList);
        }
        if (rule.getSdfCouponInfo() != null) {
            SdfCouponInfoDTO couponInfoDTO = new SdfCouponInfoDTO();
            couponInfoDTO.setCouponAmount(rule.getSdfCouponInfo().getCouponAmount());
            couponInfoDTO.setCouponTemplateId(rule.getSdfCouponInfo().getCouponTemplateId());
            couponInfoDTO.setCouponId(rule.getSdfCouponInfo().getCouponId() != null ? rule.getSdfCouponInfo().getCouponId() : 0);
            couponInfoDTO.setBenefitTemplateId(rule.getSdfCouponInfo().getBenefitTemplateId());
            ruleDTO.setSdfCouponInfo(couponInfoDTO);
        }

        return ruleDTO;
    }

    @Override
    public String toString() {
        return "SdfBenefitRule{" +
                "sdfCouponInfo=" + sdfCouponInfo +
                ", sdfRedPackStageRules=" + sdfRedPackStageRules +
                '}';
    }
}

